# Scratch: "যদি তাহলে" ব্লকের মতোই
আবহাওয়া = input("আজ আবহাওয়া কেমন? (রোদ/বৃষ্টি): ")
if আবহাওয়া == "রোদ":
    print("বাইরে খেলতে চলো!")
else:
    print("বাড়িতে প্রোগ্রামিং করি!")

# Scratch: "যদি তাহলে, না হলে যদি তাহলে" ব্লকের মতোই
ঘণ্টা = int(input("এখন কটা বাজে? (0-23): "))
if ঘণ্টা < 10:
    print("সুপ্রভাত!")
elif ঘণ্টা < 17:
    print("নমস্কার!")
else:
    print("শুভ সন্ধ্যা!")

# Scratch: "আবার করো" ব্লকের মতোই
